"""Universal AI script — works in Colab, local venv, and CI environments."""
import os
import sys

def load_api_key(key_name: str) -> str | None:
    """
    Load API key from the appropriate source:
    1. Colab Secrets (when running in Google Colab)
    2. Environment variables / .env file (local dev)
    3. Returns None if not found
    """
    # Check if we're in Colab
    try:
        from google.colab import userdata
        key = userdata.get(key_name)
        if key:
            print(f"✅ Loaded {key_name} from Colab Secrets")
            return key
    except ImportError:
        pass  # Not in Colab
    except Exception:
        pass  # Colab secret not set

    # Try .env file (local dev)
    try:
        from dotenv import load_dotenv
        load_dotenv()
    except ImportError:
        pass  # python-dotenv not installed

    key = os.getenv(key_name)
    if key:
        print(f"✅ Loaded {key_name} from environment")
        return key

    print(f"⚠️  {key_name} not found")
    return None


def detect_environment() -> str:
    """Detect where we're running."""
    try:
        import google.colab
        return "google-colab"
    except ImportError:
        pass

    if os.getenv('AWS_EXECUTION_ENV') or os.getenv('AWS_LAMBDA_FUNCTION_NAME'):
        return "aws-lambda"

    if os.getenv('GITHUB_ACTIONS'):
        return "github-actions"

    if os.getenv('CI'):
        return "ci"

    return "local"


def call_anthropic_direct(prompt: str, api_key: str) -> str | None:
    """Call Claude directly via Anthropic API."""
    import requests
    response = requests.post(
        "https://api.anthropic.com/v1/messages",
        headers={
            "x-api-key": api_key,
            "anthropic-version": "2023-06-01",
            "content-type": "application/json",
        },
        json={
            "model": "claude-haiku-4-5-20251001",
            "max_tokens": 128,
            "messages": [{"role": "user", "content": prompt}]
        },
        timeout=30
    )
    if response.status_code == 200:
        return response.json()["content"][0]["text"]
    print(f"API error: {response.status_code}")
    return None


def call_aws_bedrock(prompt: str) -> str | None:
    """Call Claude via AWS Bedrock (requires boto3 and AWS credentials)."""
    try:
        import boto3, json
        bedrock = boto3.client('bedrock-runtime', region_name='us-east-1')
        response = bedrock.invoke_model(
            modelId='anthropic.claude-3-haiku-20240307-v1:0',
            body=json.dumps({
                "messages": [{"role": "user", "content": prompt}],
                "max_tokens": 128,
                "anthropic_version": "bedrock-2023-05-31"
            })
        )
        result = json.loads(response['body'].read())
        return result['content'][0]['text']
    except Exception as e:
        print(f"Bedrock error: {e}")
        return None


if __name__ == "__main__":
    env = detect_environment()
    print(f"Environment: {env}")

    api_key = load_api_key('ANTHROPIC_API_KEY')

    prompt = "In exactly one sentence, what is Google Colab?"

    if api_key:
        print(f"\nCalling Claude with prompt: '{prompt}'")
        answer = call_anthropic_direct(prompt, api_key)
        if answer:
            print(f"Claude: {answer}")
    else:
        print("\nNo API key — showing mock response")
        print("Claude: Google Colab is a free cloud Jupyter notebook environment with GPU access.")
